2781	/// Multi-fact extension emitted by `rbw-iah` (rbfl_audit_hallmarks): one
2782	/// `<hallmark>.audit-hallmark` file per discovered hallmark. Mirrors
2783	/// rbcc_Constants.sh RBCC_fact_ext_audit_hallmark.
2784	const RBTDRC_FACT_EXT_AUDIT_HALLMARK: &str = "audit-hallmark";
2785	
2786	/// Multi-fact extension emitted by `rbw-lE` (rbld_ensconce): one
2787	/// `<touchmark>.lode` capture-file per ensconced Lode, carrying the provenance
2788	/// envelope. Its root is the Lode touchmark. Mirrors rbcc_Constants.sh
2789	/// RBCC_fact_ext_lode.
2790	const RBTDRC_FACT_EXT_LODE: &str = "lode";
2791	
2792	/// Bole-Lode member tags asserted by divine inspect. Mirror rbgc_Constants.sh
2793	/// RBGC_LODE_TAG_BOLE / RBGC_LODE_TAG_VOUCH / RBGC_LODE_TAG_DIGEST_PREFIX.
2794	const RBTDRC_LODE_TAG_BOLE: &str = "rbi_bole";
2795	const RBTDRC_LODE_TAG_VOUCH: &str = "rbi_vouch";
2796	const RBTDRC_LODE_TAG_DIGEST_PREFIX: &str = "rbi_sha256-";
2797	
2798	fn rbtdrc_hallmark_lifecycle(dir: &Path) -> rbtdre_Verdict {
2799	    rbtdrc_with_ctx(|ctx| {
2800	        let vessel_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
2801	        if !ctx.project_root().join(vessel_dir).is_dir() {
2802	            return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vessel_dir));
2803	        }
2804	
2805	        // Step 1: baseline audit.
2806	        let _ = std::fs::write(dir.join("01-audit-baseline.txt"), "auditing baseline");
2807	        let baseline_audit = match rbtdri_invoke_global(ctx, RBTDGC_AUDIT_HALLMARKS, &[], &[]) {
2808	            Ok(r) if r.exit_code == 0 => r,
2809	            Ok(r) => return rbtdre_Verdict::Fail(format!("baseline audit failed (exit {})\n{}", r.exit_code, r.stderr)),
2810	            Err(e) => return rbtdre_Verdict::Fail(format!("baseline audit invocation: {}", e)),
2811	        };
2812	        let _ = std::fs::write(dir.join("01-audit-baseline-stdout.txt"), &baseline_audit.stdout);
2813	        let baseline = match rbtdri_read_burv_facts_multi(&baseline_audit, RBTDRC_FACT_EXT_AUDIT_HALLMARK) {
2814	            Ok(v) => v,
2815	            Err(e) => return rbtdre_Verdict::Fail(format!("read baseline audit facts: {}", e)),
2816	        };
2817	        let _ = std::fs::write(dir.join("01-baseline-parsed.txt"), baseline.join("\n"));
2818	
2819	        // Step 2: ordain.
2820	        let _ = std::fs::write(dir.join("02-ordain.txt"), "ordaining busybox");
2821	        let ordain_result = match rbtdri_invoke_global(ctx, RBTDGC_ORDAIN_HALLMARK, &[vessel_dir], &[]) {
2822	            Ok(r) if r.exit_code == 0 => r,
2823	            Ok(r) => return rbtdre_Verdict::Fail(format!("ordain failed (exit {})\n{}", r.exit_code, r.stderr)),
2824	            Err(e) => return rbtdre_Verdict::Fail(format!("ordain invocation: {}", e)),
2825	        };
2826	        let hallmark = match rbtdri_read_burv_fact(&ordain_result, RBTDRC_FACT_HALLMARK) {
2827	            Ok(v) => v,
2828	            Err(e) => return rbtdre_Verdict::Fail(format!("read hallmark: {}", e)),
2829	        };
2830	        let _ = std::fs::write(dir.join("02-hallmark.txt"), &hallmark);
2831	
2832	        // Step 3: audit shows new hallmark added.
2833	        let _ = std::fs::write(dir.join("03-audit-after-ordain.txt"), "auditing after ordain");
2834	        let after_ordain_audit = match rbtdri_invoke_global(ctx, RBTDGC_AUDIT_HALLMARKS, &[], &[]) {
2835	            Ok(r) if r.exit_code == 0 => r,
2836	            Ok(r) => return rbtdre_Verdict::Fail(format!("post-ordain audit failed (exit {})\n{}", r.exit_code, r.stderr)),
2837	            Err(e) => return rbtdre_Verdict::Fail(format!("post-ordain audit invocation: {}", e)),
2838	        };
2839	        let _ = std::fs::write(dir.join("03-audit-after-ordain-stdout.txt"), &after_ordain_audit.stdout);
2840	        let after_ordain = match rbtdri_read_burv_facts_multi(&after_ordain_audit, RBTDRC_FACT_EXT_AUDIT_HALLMARK) {
2841	            Ok(v) => v,
2842	            Err(e) => return rbtdre_Verdict::Fail(format!("read post-ordain audit facts: {}", e)),
2843	        };
2844	        let mut expected_after_ordain = baseline.clone();
2845	        expected_after_ordain.push(hallmark.clone());
2846	        expected_after_ordain.sort();
2847	        if after_ordain != expected_after_ordain {
2848	            return rbtdre_Verdict::Fail(format!(
2849	                "post-ordain audit mismatch:\n  expected (baseline + new): {:?}\n  got: {:?}",
2850	                expected_after_ordain, after_ordain
2851	            ));
2852	        }
2853	
2854	        // Step 4: rekon shows all five ark basenames present.
2855	        let _ = std::fs::write(dir.join("04-rekon-after-ordain.txt"), "rekoning after ordain");
2856	        let rekon_after_ordain = match rbtdri_invoke_global(ctx, RBTDGC_REKON_HALLMARK, &[&hallmark], &[]) {
2857	            Ok(r) if r.exit_code == 0 => r,
2858	            Ok(r) => return rbtdre_Verdict::Fail(format!("post-ordain rekon failed (exit {})\n{}", r.exit_code, r.stderr)),
2859	            Err(e) => return rbtdre_Verdict::Fail(format!("post-ordain rekon invocation: {}", e)),
2860	        };
2861	        let _ = std::fs::write(dir.join("04-rekon-after-ordain-stdout.txt"), &rekon_after_ordain.stdout);
2862	        for basename in ZRBTDRC_ARK_BASENAMES_ALL {
2863	            if !rbtdrc_rekon_basename_yes(&rekon_after_ordain.stdout, basename) {
2864	                return rbtdre_Verdict::Fail(format!(
2865	                    "post-ordain rekon: basename '{}' not marked yes\nstdout:\n{}",
2866	                    basename, rekon_after_ordain.stdout
2867	                ));
2868	            }
2869	        }
2870	
2871	        // Step 5: abjure.
2872	        let _ = std::fs::write(dir.join("05-abjure.txt"), "abjuring");
2873	        match rbtdri_invoke_global(ctx, RBTDGC_ABJURE_HALLMARK, &[&hallmark], &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)]) {
2874	            Ok(r) if r.exit_code == 0 => {}
2875	            Ok(r) => return rbtdre_Verdict::Fail(format!("abjure failed (exit {})\n{}", r.exit_code, r.stderr)),
2876	            Err(e) => return rbtdre_Verdict::Fail(format!("abjure invocation: {}", e)),
2877	        }
2878	
2879	        // Step 6: rekon for the abjured hallmark must exit non-zero — the
2880	        // Unix exit contract is the assertion (rekon's display text is not
2881	        // normative). Stdout captured for diagnostic value only; never read
2882	        // for assertions.
2883	        let _ = std::fs::write(dir.join("06-rekon-after-abjure.txt"), "rekoning after abjure");
2884	        match rbtdri_invoke_global(ctx, RBTDGC_REKON_HALLMARK, &[&hallmark], &[]) {
2885	            Ok(r) if r.exit_code != 0 => {
2886	                let _ = std::fs::write(dir.join("06-rekon-after-abjure-stdout.txt"), &r.stdout);
2887	            }
2888	            Ok(r) => {
2889	                let _ = std::fs::write(dir.join("06-rekon-after-abjure-stdout.txt"), &r.stdout);
2890	                return rbtdre_Verdict::Fail(format!(
2891	                    "post-abjure rekon: expected non-zero exit, got success (exit 0)\nstdout:\n{}",
2892	                    r.stdout
2893	                ));
2894	            }
2895	            Err(e) => return rbtdre_Verdict::Fail(format!("post-abjure rekon invocation: {}", e)),
2896	        }
2897	
2898	        // Step 7: final audit — registry restored to baseline.
2899	        let _ = std::fs::write(dir.join("07-audit-final.txt"), "auditing final");
2900	        let final_audit = match rbtdri_invoke_global(ctx, RBTDGC_AUDIT_HALLMARKS, &[], &[]) {
2901	            Ok(r) if r.exit_code == 0 => r,
2902	            Ok(r) => return rbtdre_Verdict::Fail(format!("final audit failed (exit {})\n{}", r.exit_code, r.stderr)),
2903	            Err(e) => return rbtdre_Verdict::Fail(format!("final audit invocation: {}", e)),
2904	        };
2905	        let _ = std::fs::write(dir.join("07-audit-final-stdout.txt"), &final_audit.stdout);
2906	        let final_state = match rbtdri_read_burv_facts_multi(&final_audit, RBTDRC_FACT_EXT_AUDIT_HALLMARK) {
2907	            Ok(v) => v,
2908	            Err(e) => return rbtdre_Verdict::Fail(format!("read final audit facts: {}", e)),
2909	        };
2910	        if final_state != baseline {
2911	            return rbtdre_Verdict::Fail(format!(
2912	                "final audit mismatch — abjure did not restore baseline:\n  baseline: {:?}\n  final: {:?}",
2913	                baseline, final_state
2914	            ));
2915	        }
2916	
2917	        let _ = std::fs::write(dir.join("08-passed.txt"), "passed");
2918	        rbtdre_Verdict::Pass
2919	    })
2920	}
